import pytest
from solution import exit_code_for

def test_all_passing_returns_zero():
    assert exit_code_for({'passed': 10, 'failed': 0, 'errors': 0}) == 0

def test_any_failure_returns_one():
    assert exit_code_for({'passed': 9, 'failed': 1, 'errors': 0}) == 1

def test_any_error_returns_one():
    assert exit_code_for({'passed': 9, 'failed': 0, 'errors': 1}) == 1

def test_failures_and_errors_returns_one():
    assert exit_code_for({'passed': 0, 'failed': 3, 'errors': 2}) == 1

def test_missing_keys_treated_as_zero():
    assert exit_code_for({'passed': 5}) == 0

def test_empty_summary_returns_zero():
    assert exit_code_for({}) == 0
